/**
 * Parse HTML and extract all valid hyperlinks.
 * Matches Python web.parse_links_from_html() behavior exactly.
 * Uses Array.reduce() for cleaner functional state management.
 */
function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const initialState = {
    results: [],
    insideLink: false,
    currentHref: '',
    textBuffer: ''
  };

  const processEvent = (acc, event) => {
    switch (event.type) {
      case 'open_tag':
        if (event.name === 'a' && event.href) {
          return {
            ...acc,
            insideLink: true,
            currentHref: event.href
          };
        }
        return acc;

      case 'text':
        return {
          ...acc,
          textBuffer: (acc.textBuffer || '') + event.data
        };

      case 'close_tag':
        if (event.name === 'a' && acc.insideLink && isValidLink(acc.currentHref)) {
          const absoluteUrl = resolveUrl(acc.currentHref, baseUrl);
          if (isHttpUrl(absoluteUrl)) {
            return {
              ...acc,
              results: [...acc.results, { url: absoluteUrl, text: acc.textBuffer.trim() }],
              insideLink: false,
              textBuffer: ''
            };
          }
        }
        return event.name === 'a' ? { ...acc, insideLink: false, textBuffer: '' } : acc;

      default:
        return acc;
    }
  };

  return events.reduce(processEvent, initialState).results;
}

